def apply_plan(desired, state):
    return set(desired)

def pass_rate(results):
    return (sum(1 for r in results if r) / len(results)) if results else 0.0

def run_reproducible_eval(desired, cases, threshold):
    provisioned = apply_plan(desired, set())
    rate = pass_rate(cases)
    torn_down = apply_plan([], provisioned)
    return {"provisioned": sorted(provisioned), "pass_rate": round(rate, 2), "gate": rate >= threshold, "clean_teardown": len(torn_down) == 0}

